module RefModule(
    input clk,
    input parallel_load,
    input [3:0] in,
    output reg out
);reg [3:0] unused_shift_reg;

always @(posedge clk) begin
    if (parallel_load) begin
        unused_shift_reg <= in;
    end else begin
        unused_shift_reg <= {unused_shift_reg[2:0], unused_shift_reg[3]};
    end
end

assign out = unused_shift_reg[0];

endmodule
